-- ========== 9. 经验（5 条） ==========
INSERT INTO experiences (id, project_id, title, content, tags_json, status, author_id, reviewer_id, published_at, created_at, updated_at) VALUES
('f0000000-0000-4000-8000-000000000001', 'b0000000-0000-4000-8000-000000000001',
 '气体靶 80K 预冷降温操作规程',
 '1. 降温前确认真空优于 5×10⁻⁴ Pa，否则先抽真空；2. 氦气流量从 5L/min 起步，每 30 分钟增加 5L/min，上限 20L/min；3. 降温速率控制在 1~1.5K/min，避免靶体热应力；4. 80K 以下切换小流量模式，防止过冲；5. 冷头温度稳定 1 小时且波动 <±0.5K 后方可进气实验。',
 '["低温", "操作规程", "气体靶"]'::jsonb, 'published',
 'a0000000-0000-4000-8000-000000000001', 'a0000000-0000-4000-8000-000000000001',
 '2026-07-10T10:00:00+08:00', '2026-07-09T15:00:00+08:00', '2026-07-10T10:00:00+08:00'),
('f0000000-0000-4000-8000-000000000002', 'b0000000-0000-4000-8000-000000000001',
 'RF 匹配网络快速调谐经验',
 '调谐顺序先 C2（调谐）后 C1（负载）：先低功率 50W 粗调，VSWR<1.5 后升功率；每升 100W 复查一次匹配点。300W 以上注意电容温升引起的漂移，必要时提前开水冷。记录最终电容位置作为下次基准，可将调谐时间从 40 分钟缩短到 10 分钟。',
 '["RF", "匹配", "调谐"]'::jsonb, 'published',
 'a0000000-0000-4000-8000-000000000002', 'a0000000-0000-4000-8000-000000000001',
 '2026-07-12T15:00:00+08:00', '2026-07-11T10:00:00+08:00', '2026-07-12T15:00:00+08:00'),
('f0000000-0000-4000-8000-000000000003', NULL,
 '真空系统漏率排查通用流程',
 '漏率突升时按以下顺序排查：1. 确认规管读数可信（与另一规管比对）；2. 分段隔离，先关高真空阀判断漏点在泵侧还是室侧；3. 氦检漏从最近拆装过的法兰开始；4. 重点怀疑 O 圈、闸板阀和馈通件；5. 修复后静态升压法复测漏率并记录。切忌凭感觉逐一手拧法兰。',
 '["真空", "检漏", "通用"]'::jsonb, 'published',
 'a0000000-0000-4000-8000-000000000001', 'a0000000-0000-4000-8000-000000000001',
 '2026-07-08T11:00:00+08:00', '2026-07-07T16:00:00+08:00', '2026-07-08T11:00:00+08:00'),
('f0000000-0000-4000-8000-000000000004', 'b0000000-0000-4000-8000-000000000002',
 '冷冻靶温度稳定性优化建议',
 '当前冰层生长温度稳定性 ±5mK，建议：1. 控温 PID 参数在 18.2K 工作点重新整定；2. 加热丝绕组增加匀流措施；3. 温度采样周期从 1s 缩短到 200ms 观察高频扰动；4. 待下次开腔时在靶座加装第二支测温二极管做冗余比对。',
 '["低温", "冷冻靶"]'::jsonb, 'candidate',
 'a0000000-0000-4000-8000-000000000005', NULL,
 NULL, '2026-07-17T14:00:00+08:00', '2026-07-17T14:00:00+08:00'),
('f0000000-0000-4000-8000-000000000005', NULL,
 '中子探测器能谱刻度注意事项',
 'LaBr3 探测器刻度建议：1. 用 137Cs+60Co 双源覆盖 0.6~1.3MeV，2.45MeV 峰用打靶数据自刻度；2. 刻度前预热 30 分钟，高压稳定后再采谱；3. 每次换高压或搬动探测器后必须重新刻度；4. 峰位漂移超过 5 道时检查光电倍增管温度。',
 '["中子", "探测器", "刻度"]'::jsonb, 'candidate',
 'a0000000-0000-4000-8000-000000000001', NULL,
 NULL, '2026-07-18T09:00:00+08:00', '2026-07-18T09:00:00+08:00');

